flow "etl-four" v1

fetch[action: "Fetch"] {
  adapter: "shell"
  actionId: "run-command"
  command: "curl -fsS https://example.com/in.json -o /tmp/in.json"
}

validate[action: "Validate"] {
  adapter: "shell"
  actionId: "run-command"
  command: "jq -e . /tmp/in.json"
}

transform[action: "Transform"] {
  adapter: "shell"
  actionId: "run-command"
  command: "jq '{ok:true, count:length}' /tmp/in.json > /tmp/out.json"
}

post[action: "Post"] {
  adapter: "shell"
  actionId: "run-command"
  command: "curl -fsS -X POST https://example.com/out -d @/tmp/out.json"
}

fetch --> validate
validate --> transform
transform --> post

